def isBoomerang(self, points: List[List[int]]) -> bool:
    n = len(points)
    for i in range(n - 2):
        for j in range(i + 1, n - 1):
            for k in range(j + 1, n):
                if points[i][0] == points[j][0] and points[i][1] == points[k][0] and points[j][1] == points[k][1]:
                    return False
    return True

